package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.when;

import java.lang.reflect.Field;
import java.io.Reader;
import java.io.StringReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVParser parser;
    private Lexer lexerMock;

    @BeforeEach
    void setUp() throws Exception {
        // Use a real Reader instead of a mock to avoid constructor issues
        Reader reader = new StringReader("");

        // Create a CSVParser instance with a real Reader and null CSVFormat
        parser = new CSVParser(reader, null);

        // Create a mock Lexer
        lexerMock = mock(Lexer.class);

        // Inject the mock Lexer into the private final lexer field using reflection
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(parser, lexerMock);
    }

    @Test
    void testGetCurrentLineNumber() {
        long expectedLineNumber = 123L;
        when(lexerMock.getCurrentLineNumber()).thenReturn(expectedLineNumber);

        long actualLineNumber = parser.getCurrentLineNumber();

        assertEquals(expectedLineNumber, actualLineNumber);
    }
}
